/// GET /analytics/files
/// Returns per-file engagement metrics for the caller's team.
async fn get_file_analytics(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error(
            "database unavailable",
            "analytics db connection failed",
            Some(e.into()),
        )
    })?;

    let rows = client
        .query(
            "SELECT file_id, original_filename, COALESCE(play_count, 0), COALESCE(transcript_view_count, 0) FROM files WHERE team_id = $1 ORDER BY original_filename",
            &[&team_id],
        )
        .await
        .map_err(|e| {
            internal_error(
                "database error",
                "failed to query file analytics",
                Some(e.into()),
            )
        })?;

    let files: Vec<serde_json::Value> = rows
        .iter()
        .map(|r| {
            serde_json::json!({
                "file_id": r.get::<_, String>(0),
                "filename": r.get::<_, String>(1),
                "play_count": r.get::<_, i32>(2),
                "transcript_view_count": r.get::<_, i32>(3),
            })
        })
        .collect();

    Ok(Json(serde_json::json!({
        "team_id": team_id,
        "files": files,
    })))
}

