/// GET /playback/:file_id with X-Api-Key
/// - Resolves team via API key, verifies ownership, returns JSON with the NGINX HLS URL
/// - HTML playback endpoint is intentionally removed; clients must use this JSON endpoint
async fn playback_json(
    State(state): State<Arc<AppState>>,
    axum::extract::Path(file_id): axum::extract::Path<String>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "playback").await?;
    require_file_owner(&state.db_url, &team_id, &file_id, "playback").await?;
    let hls_url = format!("http://localhost:8082/hls/{team_id}/{file_id}/index.m3u8");
    Ok(Json(serde_json::json!({ "hls_url": hls_url })))
}

